import 'package:coconut_lib/coconut_lib.dart';
import 'package:mockito/mockito.dart';

import 'mock_factory.dart';

void main() {
  NetworkType.setNetworkType(NetworkType.regtest);
  SingleSignatureVault vault = MockFactory.createThankVault();

  String unsignedPsbtText1 =
      '';

  String unsignedPsbtText2 =
      '';

  // ** Diagonasis
  String signedTx1 =
      '';

  String signedTx2 =
      '';

  Transaction beforeTx1 = Transaction.parse(signedTx1);
  Transaction beforeTx2 = Transaction.parse(signedTx2);

  int i = 0;
  print("Test 1:");
  for (TransactionInput input in beforeTx1.inputs) {
    String signature = input.witnessList[0];
    if (!isCanonicalDerSignatureHex(signature)) {
      print("$i : $signature");
    }
    i++;
  }
  i = 0;
  print("Test 2:");
  for (TransactionInput input in beforeTx2.inputs) {
    String signature = input.witnessList[0];
    if (!isCanonicalDerSignatureHex(signature)) {
      print("$i : $signature");
    }
    i++;
  }

  // ** After solution
  Transaction afterTx1 = Psbt.parse(vault.addSignatureToPsbt(unsignedPsbtText1))
      .getSignedTransaction(vault.addressType);
  Transaction afterTx2 = Psbt.parse(vault.addSignatureToPsbt(unsignedPsbtText1))
      .getSignedTransaction(vault.addressType);

  print("Test 1:");
  for (TransactionInput input in afterTx1.inputs) {
    String signature = input.witnessList[0];
    if (!isCanonicalDerSignatureHex(signature)) {
      print("$i : $signature");
    }
    i++;
  }
  i = 0;
  print("Test 2:");
  for (TransactionInput input in afterTx2.inputs) {
    String signature = input.witnessList[0];
    if (!isCanonicalDerSignatureHex(signature)) {
      print("$i : $signature");
    }
    i++;
  }
}

final BigInt secp256k1N = BigInt.parse(
  'FFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFEBAAEDCE6AF48A03BBFD25E8CD0364141',
  radix: 16,
);
final BigInt halfCurveOrder = secp256k1N >> 1;

bool isCanonicalDerSignatureHex(String hex) {
  final der = Codec.decodeHex(hex);
  if (der.length < 9 || der[0] != 0x30) return false;

  // int totalLen = der[1];
  // if (totalLen != der.length - 2) return false;

  if (der[2] != 0x02) return false;
  int rLen = der[3];
  if (rLen == 0 || 4 + rLen >= der.length) return false;

  if (der[4] & 0x80 != 0) return false; // R negative
  if (rLen > 1 && der[4] == 0x00 && (der[5] & 0x80) == 0)
    return false; // R unnecessary 0x00

  int sIndex = 4 + rLen;
  if (sIndex >= der.length || der[sIndex] != 0x02) return false;
  int sLen = der[sIndex + 1];
  // if (sLen == 0 || sIndex + 2 + sLen != der.length) {
  //   print("5");
  //   return false;
  // }

  if (der[sIndex + 2] & 0x80 != 0) return false; // S negative
  if (sLen > 1 && der[sIndex + 2] == 0x00 && (der[sIndex + 3] & 0x80) == 0) {
    return false; // S unnecessary 0x00
  }

  BigInt s = BigInt.parse(
    der
        .sublist(sIndex + 2, sIndex + 2 + sLen)
        .map((b) => b.toRadixString(16).padLeft(2, '0'))
        .join(),
    radix: 16,
  );
  if (s > halfCurveOrder) return false;

  return true;
}
